use std::collections::VecDeque;

struct WriteAheadLog {
    buffer: VecDeque<String>,
}

impl WriteAheadLog {
    fn new() -> Self {
        WriteAheadLog { buffer: VecDeque::new() }
    }

    fn append_record(&mut self, record: String) {
        self.buffer.push_back(record);
    }

    fn flush_to_disk(&mut self) -> usize {
        let count = self.buffer.len();
        self.buffer.clear();
        count
    }
}

fn main() {
    let mut wal = WriteAheadLog::new();
    wal.append_record("KEY1:VALUEA".to_string());
    wal.append_record("KEY2:VALUEB".to_string());
    wal.append_record("KEY3:VALUEC".to_string());

    let records_written = wal.flush_to_disk();
    println!("Successfully flushed {} records to the log.", records_written);
}

use std::iter;

struct MemoryBlock<T> { 
    data: Vec<T>
}
impl<T> MemoryBlock<T> { 
    fn new(initial_capacity: usize) -> Self {
        MemoryBlock { data: Vec::with_capacity(initial_capacity) }
    }

    fn add_item(&mut self, item: T) -> Result<(), &'static str> {
        if self.data.len() >= 1024 {
            return Err("Capacity exceeded for this chunk.");
        }
        self.data.push(item);
        Ok(())
    }
}

fn process_world_chunks<T: std::fmt::Debug>(items: impl Iterator<Item = T>) -> usize {
    let mut block = MemoryBlock::new(1024);
    let mut total_estimated_size = 0;

    for item in items.collect::<Vec<T>>().into_iter() {
        total_estimated_size += std::mem::size_of::<T>();
        if let Err(e) = block.add_item(item) {
            println!("Error processing chunk: {}", e);
        }
    }
    total_estimated_size
}

fn main() {
    let map_data = vec![10u32, 20u32, 30u32, 40u32];
    let iterator_source = map_data.into_iter();

    let final_size = process_world_chunks(iterator_source);
    println!("Total estimated size processed: {} bytes", final_size);
}
